      "id": "arc-200-public-health-data-modernization-and-ai-architecture",
      "title": "Public Health Data Modernization and AI Architecture",
      "source_heading": "Module 1. Public Health Data Modernization and AI Architecture",
      "source_collection": "Technical Architecture Track: Modules 1-10",
