      "id": "arc-310-prompt-engineering-for-technical-public-health-work",
      "title": "Prompt Engineering for Technical Public Health Work",
      "source_heading": "Module 18. Prompt Engineering for Technical Public Health Work",
      "source_collection": "Analytics, Modeling, Security, and Advanced Methods: Modules 11-20",
