      "id": "ops-300-mlops-and-llmops-for-public-health",
      "title": "MLOps and LLMOps for Public Health",
      "source_heading": "Module 24. MLOps and LLMOps for Public Health",
      "source_collection": "Operations, Privacy, Procurement, and Value Measurement: Modules 21-30",
